## Tests

Create `apps/client/src/layers/entities/session/model/__tests__/session-chat-store.test.ts`:

```typescript
import { describe, it, expect, beforeEach } from 'vitest';
import { useSessionChatStore, DEFAULT_SESSION_STATE } from '../session-chat-store';

describe('useSessionChatStore', () => {
  beforeEach(() => {
    useSessionChatStore.setState({ sessions: {}, sessionAccessOrder: [] });
  });

  it('initializes session with default state', () => {
    const { initSession, getSession } = useSessionChatStore.getState();
    initSession('s1');
    const session = getSession('s1');
    expect(session.status).toBe('idle');
    expect(session.messages).toEqual([]);
    expect(session.input).toBe('');
    expect(session.hasUnseenActivity).toBe(false);
  });

  it('does not overwrite existing session on re-init', () => {
    const { initSession, updateSession, getSession } = useSessionChatStore.getState();
    initSession('s1');
    updateSession('s1', { input: 'draft text' });
    initSession('s1');
    expect(getSession('s1').input).toBe('draft text');
  });

  it('updates session fields via updateSession', () => {
    const { initSession, updateSession, getSession } = useSessionChatStore.getState();
    initSession('s1');
    updateSession('s1', { status: 'streaming', input: 'hello' });
    const session = getSession('s1');
    expect(session.status).toBe('streaming');
    expect(session.input).toBe('hello');
  });

  it('auto-initializes session on updateSession if not present', () => {
    const { updateSession, getSession } = useSessionChatStore.getState();
    updateSession('new-session', { input: 'test' });
    expect(getSession('new-session').input).toBe('test');
    expect(getSession('new-session').status).toBe('idle');
  });

  it('renames session atomically preserving all state', () => {
    const { initSession, updateSession, renameSession, getSession } = useSessionChatStore.getState();
    initSession('old-id');
    updateSession('old-id', { input: 'my draft', status: 'streaming' });
    renameSession('old-id', 'new-id');
    expect(getSession('new-id').input).toBe('my draft');
    expect(getSession('new-id').status).toBe('streaming');
    expect(getSession('old-id')).toEqual(DEFAULT_SESSION_STATE);
  });

  it('renameSession updates sessionAccessOrder', () => {
    const { initSession, renameSession } = useSessionChatStore.getState();
    initSession('s1');
    initSession('s2');
    renameSession('s1', 's1-new');
    const { sessionAccessOrder } = useSessionChatStore.getState();
    expect(sessionAccessOrder).toContain('s1-new');
    expect(sessionAccessOrder).not.toContain('s1');
  });

  it('evicts oldest idle sessions beyond MAX_RETAINED_SESSIONS', () => {
    const { initSession, touchSession } = useSessionChatStore.getState();
    // Create 21 sessions
    for (let i = 0; i < 21; i++) {
      initSession(`s${i}`);
    }
    // Touch the 21st to trigger eviction
    touchSession('s20');
    const { sessions, sessionAccessOrder } = useSessionChatStore.getState();
    expect(sessionAccessOrder.length).toBeLessThanOrEqual(20);
    // The first session should have been evicted (oldest idle)
    expect(sessions['s0']).toBeUndefined();
  });

  it('never evicts sessions with status === streaming', () => {
    const { initSession, updateSession, touchSession } = useSessionChatStore.getState();
    // Fill to capacity
    for (let i = 0; i < 20; i++) {
      initSession(`s${i}`);
    }
    // Mark the oldest as streaming
    updateSession('s0', { status: 'streaming' });
    // Add one more to trigger eviction
    initSession('s20');
    const { sessions } = useSessionChatStore.getState();
    // s0 should survive because it's streaming
    expect(sessions['s0']).toBeDefined();
    expect(sessions['s0'].status).toBe('streaming');
  });

  it('tracks access order for LRU eviction', () => {
    const { initSession, touchSession } = useSessionChatStore.getState();
    initSession('s1');
    initSession('s2');
    initSession('s3');
    touchSession('s1'); // s1 is now most recent
    const { sessionAccessOrder } = useSessionChatStore.getState();
    expect(sessionAccessOrder[0]).toBe('s1');
  });

  it('destroySession removes session and access order entry', () => {
    const { initSession, destroySession, getSession } = useSessionChatStore.getState();
    initSession('s1');
    destroySession('s1');
    expect(getSession('s1')).toEqual(DEFAULT_SESSION_STATE);
    const { sessionAccessOrder } = useSessionChatStore.getState();
    expect(sessionAccessOrder).not.toContain('s1');
  });

  it('getSession returns default state for unknown sessionId', () => {
    const { getSession } = useSessionChatStore.getState();
    expect(getSession('nonexistent')).toEqual(DEFAULT_SESSION_STATE);
  });
});
```

## Acceptance Criteria

- [ ] `session-chat-store.ts` exists at `apps/client/src/layers/entities/session/model/session-chat-store.ts`
- [ ] Uses `immer` middleware for nested updates and `devtools` middleware gated on `import.meta.env.DEV`
- [ ] No `persist` middleware (messages must not reach localStorage)
- [ ] `SessionState` interface matches all fields from the spec (messages, currentParts, orphanHooks, assistantId, assistantCreated, pendingUserId, input, status, error, sessionBusy, streamStartTime, estimatedTokens, isTextStreaming, thinkingStart, sessionStatus, rateLimitRetryAfter, isRateLimited, systemStatus, promptSuggestions, presenceInfo, presencePulse, historySeeded, retryCount, isRemapping, hasUnseenActivity)
- [ ] `MAX_RETAINED_SESSIONS = 20`
- [ ] LRU eviction in `touchSession` skips sessions where `status === 'streaming'`
- [ ] `renameSession` atomically swaps keys and updates `sessionAccessOrder`
- [ ] `getSession` returns `DEFAULT_SESSION_STATE` for unknown session IDs
- [ ] `updateSession` auto-initializes session if not present
- [ ] Selector hooks (`useSessionChatState`, `useSessionMessages`, `useSessionStatus`) use `useCallback` for memoization
- [ ] Entity barrel (`entities/session/index.ts`) updated with exports
- [ ] All 10 unit tests pass
- [ ] `pnpm typecheck` passes

Create the `StreamManager` class at `apps/client/src/layers/features/chat/model/stream-manager.ts` as a module-level singleton that owns `AbortController` instances per session, manages timers, and dispatches stream events to the session chat store.

## Implementation

Create `apps/client/src/layers/features/chat/model/stream-manager.ts`:

```typescript
/**
 * Singleton service that manages concurrent SSE streams across sessions.
 *
 * Owns AbortController instances, streaming timers, and event dispatch.
 * Follows the module-level singleton pattern of SSEConnection and
 * AdapterStreamManager (ADR-0179).
 *
 * @module features/chat/model/stream-manager
 */
import type { Transport } from '@dorkos/shared/transport';
import type { TaskUpdateEvent, UiState } from '@dorkos/shared/types';
import type { Session } from '@dorkos/shared/types';
import { useSessionChatStore } from '@/layers/entities/session';
import { useAppStore } from '@/layers/shared/model';
import { TIMING, SSE_RESILIENCE } from '@/layers/shared/lib';
import { insertOptimisticSession } from '@/layers/entities/session';
import type { QueryClient } from '@tanstack/react-query';
import { classifyTransportError } from './classify-transport-error';
import { createStreamEventHandler } from './stream-event-handler';

export interface StreamOptions {
  cwd?: string;
  clientMessageId?: string;
  uiState?: UiState;
  transformContent?: (content: string) => string | Promise<string>;
  onSessionIdChange?: (newId: string) => void;
  onStreamingDone?: () => void;
  onTaskEvent?: (event: TaskUpdateEvent) => void;
  queryClient?: QueryClient;
}

interface SessionTimers {
  textStreaming: ReturnType<typeof setTimeout> | null;
  systemStatus: ReturnType<typeof setTimeout> | null;
  sessionBusy: ReturnType<typeof setTimeout> | null;
  presencePulse: ReturnType<typeof setTimeout> | null;
}
```

### StreamManager class

```typescript
export class StreamManager {
  private activeStreams = new Map<string, AbortController>();
  private timers = new Map<string, SessionTimers>();

  /** Start a streaming request for a session. Aborts any existing stream for the same session. */
  async start(
    sessionId: string,
    content: string,
    transport: Transport,
    options: StreamOptions
  ): Promise<void> {
    // 1. Abort any existing stream for this session
    this.abort(sessionId);

    // 2. Create new AbortController
    const controller = new AbortController();
    this.activeStreams.set(sessionId, controller);

    // 3. Initialize store state for streaming
    const store = useSessionChatStore.getState();
    const pendingUserId = `pending-user-${crypto.randomUUID()}`;
    const assistantId = crypto.randomUUID();

    store.updateSession(sessionId, {
      status: 'streaming',
      error: null,
      retryCount: 0,
      currentParts: [],
      assistantId,
      assistantCreated: false,
      pendingUserId,
      streamStartTime: Date.now(),
      estimatedTokens: 0,
    });

    // 4. Add optimistic user message
    const session = store.getSession(sessionId);
    store.updateSession(sessionId, {
      messages: [
        ...session.messages,
        {
          id: pendingUserId,
          role: 'user' as const,
          content,
          parts: [{ type: 'text', text: content }],
          timestamp: new Date().toISOString(),
          _streaming: true,
        },
      ],
    });

    // 5. Insert optimistic session into TanStack Query cache if new
    if (options.queryClient) {
      const cwd = options.cwd ?? null;
      const sessions = options.queryClient.getQueryData<Session[]>(['sessions', cwd]) ?? [];
      if (!sessions.some((s) => s.id === sessionId)) {
        const now = new Date().toISOString();
        insertOptimisticSession(options.queryClient, cwd, {
          id: sessionId,
          title: `Session ${sessionId.slice(0, 8)}`,
          createdAt: now,
          updatedAt: now,
          permissionMode: 'default',
        });
      }
    }

    // 6. Call transport.sendMessage with event handler
    try {
      const finalContent = options.transformContent
        ? await options.transformContent(content)
        : content;

      const uiState = options.uiState ?? this.snapshotUiState(options.cwd ?? null);

      await transport.sendMessage(
        sessionId,
        finalContent,
        (event) => this.dispatchEvent(sessionId, event.type, event.data, assistantId, options),
        controller.signal,
        options.cwd,
        { clientMessageId: pendingUserId, uiState }
      );

      store.updateSession(sessionId, { status: 'idle', pendingUserId: null });
    } catch (err) {
      if ((err as Error).name === 'AbortError') {
        this.resetStreamingState(sessionId);
        return;
      }

      const errorInfo = classifyTransportError(err);
      const currentSession = store.getSession(sessionId);

      // Session locked -- restore input and show auto-dismissing banner
      if ((err as { code?: string }).code === 'SESSION_LOCKED') {
        if (currentSession.pendingUserId) {
          const failedId = currentSession.pendingUserId;
          store.updateSession(sessionId, {
            messages: currentSession.messages.filter((m) => m.id !== failedId),
            pendingUserId: null,
          });
        }
        store.updateSession(sessionId, {
          sessionBusy: true,
          error: errorInfo,
          input: content, // Restore input
          status: 'error',
        });
        const timers = this.getOrCreateTimers(sessionId);
        if (timers.sessionBusy) clearTimeout(timers.sessionBusy);
        timers.sessionBusy = setTimeout(() => {
          store.updateSession(sessionId, { sessionBusy: false, error: null });
          timers.sessionBusy = null;
        }, TIMING.SESSION_BUSY_CLEAR_MS);
        this.resetStreamingState(sessionId);
        return;
      }

      // Retryable transient error -- auto-retry before surfacing to user
      const hasPartialResponse = currentSession.assistantCreated;
      if (
        errorInfo.retryable &&
        !hasPartialResponse &&
        currentSession.retryCount < SSE_RESILIENCE.POST_MAX_RETRIES
      ) {
        store.updateSession(sessionId, {
          retryCount: currentSession.retryCount + 1,
          error: { heading: 'Connection interrupted', message: 'Retrying...', retryable: false },
        });

        await new Promise((resolve) => setTimeout(resolve, SSE_RESILIENCE.POST_RETRY_DELAY_MS));

        try {
          const retryContent = options.transformContent
            ? await options.transformContent(content)
            : content;
          const retrySession = store.getSession(sessionId);

          await transport.sendMessage(
            sessionId,
            retryContent,
            (event) => this.dispatchEvent(sessionId, event.type, event.data, assistantId, options),
            controller.signal,
            options.cwd,
            {
              clientMessageId: retrySession.pendingUserId ?? pendingUserId,
              uiState: this.snapshotUiState(options.cwd ?? null),
            }
          );

          store.updateSession(sessionId, {
            pendingUserId: null,
            retryCount: 0,
            error: null,
            status: 'idle',
          });
          this.resetStreamingState(sessionId);
          return;
        } catch (retryErr) {
          if ((retryErr as Error).name === 'AbortError') {
            this.resetStreamingState(sessionId);
            return;
          }
          const retrySession = store.getSession(sessionId);
          if (retrySession.pendingUserId) {
            store.updateSession(sessionId, {
              messages: retrySession.messages.filter((m) => m.id !== retrySession.pendingUserId),
              pendingUserId: null,
            });
          }
          store.updateSession(sessionId, {
            error: classifyTransportError(retryErr),
            status: 'error',
          });
          this.resetStreamingState(sessionId);
          return;
        }
      }

      // Non-retryable or retries exhausted
      if (currentSession.pendingUserId) {
        store.updateSession(sessionId, {
          messages: currentSession.messages.filter((m) => m.id !== currentSession.pendingUserId),
          pendingUserId: null,
        });
      }

      const displayError =
        hasPartialResponse && errorInfo.retryable
          ? {
              heading: 'Response interrupted',
              message: 'The connection was lost mid-response. The partial response is preserved above.',
              retryable: true,
            }
          : errorInfo;

      store.updateSession(sessionId, { error: displayError, status: 'error' });
      this.resetStreamingState(sessionId);
    } finally {
      this.activeStreams.delete(sessionId);
    }
  }

  /** Abort a specific session's stream. */
  abort(sessionId: string): void {
    this.activeStreams.get(sessionId)?.abort();
    this.activeStreams.delete(sessionId);
    this.clearTimers(sessionId);
  }

  /** Abort all active streams. */
  abortAll(): void {
    for (const [id, controller] of this.activeStreams) {
      controller.abort();
      this.clearTimers(id);
    }
    this.activeStreams.clear();
  }

  /** Check if a session has an active stream. */
  isStreaming(sessionId: string): boolean {
    return this.activeStreams.has(sessionId);
  }

  /** Get all session IDs with active streams. */
  getActiveSessionIds(): string[] {
    return [...this.activeStreams.keys()];
  }

  /** Route SSE events to store updates. */
  private dispatchEvent(
    sessionId: string,
    type: string,
    data: unknown,
    assistantId: string,
    options: StreamOptions
  ): void {
    // Phase 1+2: delegate to the existing createStreamEventHandler.
    // The handler still receives setState-shaped deps, but we bridge them
    // to store calls. Full migration happens in Phase 3+4.
    // For now, this is a passthrough that calls the event handler
    // which writes to the store via the bridged deps.
  }

  private resetStreamingState(sessionId: string): void {
    const timers = this.timers.get(sessionId);
    if (timers?.textStreaming) clearTimeout(timers.textStreaming);
    const store = useSessionChatStore.getState();
    store.updateSession(sessionId, {
      isTextStreaming: false,
      isRateLimited: false,
      rateLimitRetryAfter: null,
    });
  }

  private clearTimers(sessionId: string): void {
    const timers = this.timers.get(sessionId);
    if (!timers) return;
    if (timers.textStreaming) clearTimeout(timers.textStreaming);
    if (timers.systemStatus) clearTimeout(timers.systemStatus);
    if (timers.sessionBusy) clearTimeout(timers.sessionBusy);
    if (timers.presencePulse) clearTimeout(timers.presencePulse);
    this.timers.delete(sessionId);
  }

  private getOrCreateTimers(sessionId: string): SessionTimers {
    let timers = this.timers.get(sessionId);
    if (!timers) {
      timers = { textStreaming: null, systemStatus: null, sessionBusy: null, presencePulse: null };
      this.timers.set(sessionId, timers);
    }
    return timers;
  }

  private snapshotUiState(activeCwd: string | null): UiState {
    const s = useAppStore.getState();
    return {
      canvas: { open: s.canvasOpen, contentType: s.canvasContent?.type ?? null },
      panels: { settings: s.settingsOpen, pulse: s.pulseOpen, relay: s.relayOpen, mesh: s.meshOpen },
      sidebar: { open: s.sidebarOpen, activeTab: s.sidebarActiveTab },
      agent: { id: null, cwd: activeCwd },
    };
  }
}

/** Module-level singleton instance. */
export const streamManager = new StreamManager();
```

