```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { StreamManager } from '../stream-manager';

describe('Multi-session streaming', () => {
  let manager: StreamManager;

  beforeEach(() => {
    manager = new StreamManager();
  });

  it('switching sessions while streaming does NOT abort background stream', () => {
    // 1. Start a stream for session A (set up controller manually)
    const controllerA = new AbortController();
    const abortSpyA = vi.spyOn(controllerA, 'abort');
    (manager as any).activeStreams.set('session-a', controllerA);

    // 2. Verify session A is streaming
    expect(manager.isStreaming('session-a')).toBe(true);

    // 3. "Switch" to session B -- this is just changing the active session
    // In the real app, this changes the URL/sessionId, NOT the StreamManager state.
    // StreamManager.abort is NOT called -- that's the key invariant.

    // 4. Verify session A's stream was NOT aborted
    expect(abortSpyA).not.toHaveBeenCalled();
    expect(manager.isStreaming('session-a')).toBe(true);

    // 5. Session B can also start streaming concurrently
    const controllerB = new AbortController();
    (manager as any).activeStreams.set('session-b', controllerB);
    expect(manager.isStreaming('session-b')).toBe(true);
    expect(manager.isStreaming('session-a')).toBe(true);
    expect(manager.getActiveSessionIds()).toHaveLength(2);
  });

  it('aborting session A does not affect session B', () => {
    const controllerA = new AbortController();
    const controllerB = new AbortController();
    const abortSpyB = vi.spyOn(controllerB, 'abort');
    (manager as any).activeStreams.set('session-a', controllerA);
    (manager as any).activeStreams.set('session-b', controllerB);

    manager.abort('session-a');

    expect(manager.isStreaming('session-a')).toBe(false);
    expect(manager.isStreaming('session-b')).toBe(true);
    expect(abortSpyB).not.toHaveBeenCalled();
  });
});
```

