### Step 1: Create the indicator component

Add the component directly in `SessionItem.tsx` (it's small enough to be co-located):

```typescript
import { useCallback } from 'react';
import { useSessionChatStore } from '@/layers/entities/session';

/** Background activity dot indicator for sidebar session items. */
function SessionActivityIndicator({ sessionId }: { sessionId: string }) {
  const status = useSessionChatStore(
    useCallback((s) => s.sessions[sessionId]?.status ?? 'idle', [sessionId])
  );
  const hasUnseenActivity = useSessionChatStore(
    useCallback((s) => s.sessions[sessionId]?.hasUnseenActivity ?? false, [sessionId])
  );
  const isWaitingForUser = useSessionChatStore(
    useCallback((s) => {
      const msgs = s.sessions[sessionId]?.messages ?? [];
      return msgs.some((m) =>
        m.toolCalls?.some((tc) => tc.interactiveType && tc.status === 'pending')
      );
    }, [sessionId])
  );

  if (status === 'streaming') {
    return <span className="bg-green-500 h-2 w-2 rounded-full animate-pulse" aria-label="Streaming" />;
  }
  if (status === 'error') {
    return <span className="bg-destructive h-2 w-2 rounded-full" aria-label="Error" />;
  }
  if (isWaitingForUser) {
    return <span className="bg-amber-500 h-2 w-2 rounded-full animate-pulse" aria-label="Waiting for approval" />;
  }
  if (hasUnseenActivity) {
    return <span className="bg-blue-500 h-1.5 w-1.5 rounded-full" aria-label="New activity" />;
  }
  return null;
}
```

