## Implementation

### Step 1: Remove messages useState and messagesRef

In `use-chat-session.ts`, remove:
```typescript
const [messages, setMessages] = useState<ChatMessage[]>([]);
const messagesRef = useRef<ChatMessage[]>(messages);
useEffect(() => { messagesRef.current = messages; }, [messages]);
```

Replace with store read:
```typescript
const messages = useSessionChatStore(
  useCallback((s) => s.sessions[sessionId ?? '']?.messages ?? [], [sessionId])
);
```

### Step 2: Update stream-event-helpers.ts

The `ensureAssistantMessage` and `updateAssistantMessage` functions currently call `setMessages`. Change them to write to the store:

**Before (`createStreamHelpers`):**
```typescript
function ensureAssistantMessage(assistantId: string) {
  if (!assistantCreatedRef.current) {
    assistantCreatedRef.current = true;
    setMessages((prev) => [...prev, { id: assistantId, role: 'assistant', ... }]);
  }
}
```

**After:**
```typescript
function ensureAssistantMessage(assistantId: string) {
  const store = useSessionChatStore.getState();
  const session = store.getSession(sessionId);
  if (!session.assistantCreated) {
    store.updateSession(sessionId, {
      assistantCreated: true,
      messages: [
        ...session.messages,
        {
          id: assistantId,
          role: 'assistant',
          content: '',
          toolCalls: [],
          parts: [],
          timestamp: new Date().toISOString(),
          _streaming: true,
        },
      ],
    });
  }
}

function updateAssistantMessage(assistantId: string) {
  ensureAssistantMessage(assistantId);
  const store = useSessionChatStore.getState();
  const session = store.getSession(sessionId);
  const parts = session.currentParts.map((p) => ({ ...p }));
  const derived = deriveFromParts(parts);
  store.updateSession(sessionId, {
    messages: session.messages.map((m) =>
      m.id === assistantId
        ? {
            ...m,
            content: derived.content,
            toolCalls: derived.toolCalls.length > 0 ? derived.toolCalls : [],
            parts,
          }
        : m
    ),
  });
}
```

