### Step 8: Update markToolCallResponded

Currently reads from `currentPartsRef` and calls `setMessages`. Update to read/write store:

```typescript
const markToolCallResponded = useCallback(
  (toolCallId: string) => {
    if (!sessionId) return;
    const store = useSessionChatStore.getState();
    const session = store.getSession(sessionId);
    const part = session.currentParts.find(
      (p) => p.type === 'tool_call' && p.toolCallId === toolCallId
    );
    if (part && part.type === 'tool_call') {
      const updatedParts = session.currentParts.map((p) =>
        p.type === 'tool_call' && p.toolCallId === toolCallId
          ? { ...p, status: 'running' as const }
          : { ...p }
      );
      const derived = deriveFromParts(updatedParts);
      store.updateSession(sessionId, {
        currentParts: updatedParts,
        messages: session.messages.map((m) =>
          m.id === session.assistantId
            ? {
                ...m,
                content: derived.content,
                toolCalls: derived.toolCalls.length > 0 ? derived.toolCalls : [],
                parts: updatedParts,
              }
            : m
        ),
      });
    }
  },
  [sessionId]
);
```

